161→func (h *Handler) handleAnalyze(resp Response, req Request) Response {
162→	if req.File == "" {
163→		resp.Status = "error"
164→		resp.Code = ErrInvalidRequest
165→		resp.Message = "analyze command requires a file path"
166→		return resp
167→	}
168→
169→	if _, err := os.Stat(req.File); err != nil {
170→		resp.Status = "error"
171→		resp.Code = ErrFileNotFound
172→		resp.Message = fmt.Sprintf("file not found: %s", req.File)
173→		return resp
174→	}
175→
176→	h.lastAnalyzedFile = req.File
177→
178→	var functionName string
179→	if req.Function != nil {
180→		functionName = *req.Function
181→	}
182→
183→	functions, err := AnalyzeFile(req.File, functionName)
184→	if err != nil {
185→		if functionName != "" && isNotFound(err) {
186→			resp.Status = "error"
187→			resp.Code = ErrFunctionNotFound
188→			resp.Message = fmt.Sprintf("function %q not found in %s", functionName, req.File)
189→			return resp
190→		}
191→		resp.Status = "error"
192→		resp.Code = ErrParseError
193→		resp.Message = err.Error()
194→		return resp
195→	}
196→
197→	resp.Status = "analyze"
198→	if functions == nil {
199→		functions = []FunctionAnalysis{}
200→	}
201→	resp.Functions = functions
202→	return resp
203→}
204→
205→func isNotFound(err error) bool {
206→	return err != nil && strings.HasPrefix(err.Error(), "function not found")
207→}
