411→func (h *Handler) handleSetup(resp Response, req Request) Response {
412→	if req.File == "" {
413→		resp.Status = "error"
414→		resp.Code = ErrInvalidRequest
415→		resp.Message = "setup command requires a file path"
416→		return resp
417→	}
418→	if req.Scope == "" {
419→		resp.Status = "error"
420→		resp.Code = ErrInvalidRequest
421→		resp.Message = "setup command requires a scope"
422→		return resp
423→	}
424→	if !req.Level.IsValid() {
425→		resp.Status = "error"
426→		resp.Code = ErrInvalidRequest
427→		resp.Message = fmt.Sprintf("setup command requires a valid level, got %q", req.Level)
428→		return resp
429→	}
430→
431→	if _, err := os.Stat(req.File); err != nil {
432→		resp.Status = "error"
433→		resp.Code = ErrFileNotFound
434→		resp.Message = fmt.Sprintf("setup file not found: %s", req.File)
435→		return resp
436→	}
437→
438→	var parentCtxJSON json.RawMessage
439→	if req.ParentContext != nil {
440→		data, err := json.Marshal(req.ParentContext)
441→		if err != nil {
442→			resp.Status = "error"
443→			resp.Code = ErrInternalError
444→			resp.Message = fmt.Sprintf("marshaling parent context: %v", err)
445→			return resp
446→		}
447→		parentCtxJSON = data
448→	}
449→
450→	h.log.Debug("Running setup", "file", req.File, "scope", req.Scope, "level", req.Level)
451→
452→	ctx, err := h.setupLoader.RunSetup(req.File, req.Scope, string(req.Level), req.ProjectRoot, parentCtxJSON)
453→	if err != nil {
454→		resp.Status = "error"
455→		resp.Code = ErrInternalError
456→		resp.Message = fmt.Sprintf("setup failed: %v", err)
457→		return resp
458→	}
459→
460→	resp.Status = "setup"
461→	ctxCopy := json.RawMessage(ctx)
462→	resp.SetupContext = &ctxCopy
463→	return resp
464→}
465→
466→func (h *Handler) handleTeardown(resp Response, req Request) Response {
467→	if req.Scope == "" {
468→		resp.Status = "error"
469→		resp.Code = ErrInvalidRequest
470→		resp.Message = "teardown command requires a scope"
471→		return resp
472→	}
473→	if !req.Level.IsValid() {
474→		resp.Status = "error"
475→		resp.Code = ErrInvalidRequest
476→		resp.Message = fmt.Sprintf("teardown command requires a valid level, got %q", req.Level)
477→		return resp
478→	}
479→
480→	h.log.Debug("Running teardown", "scope", req.Scope, "level", req.Level)
481→
482→	found := h.setupLoader.Teardown(req.Scope, string(req.Level))
483→	if !found {
484→		resp.Status = "error"
485→		resp.Code = ErrInternalError
486→		resp.Message = fmt.Sprintf("No setup context found for %s:%s. Call setup first.", req.Level, req.Scope)
487→		return resp
488→	}
489→
490→	// Clear stale session state so the next setup/execute cycle starts clean.
491→	h.lastAnalyzedFile = ""
492→	h.registry.Handles.Clear()
493→
494→	resp.Status = "teardown_ack"
495→	return resp
496→}
497→
498→func (h *Handler) handleGenerate(resp Response, req Request) Response {
499→	if req.File == "" {
500→		resp.Status = "error"
501→		resp.Code = ErrInvalidRequest
502→		resp.Message = "generate command requires a file path"
503→		return resp
504→	}
505→	if req.Name == "" {
506→		resp.Status = "error"
507→		resp.Code = ErrInvalidRequest
508→		resp.Message = "generate command requires a name"
509→		return resp
510→	}
511→
512→	var recipe json.RawMessage
513→	if req.Recipe != nil {
514→		recipe = *req.Recipe
515→	}
516→
517→	value, generatorID, outRecipe, err := h.registry.Generate(req.File, req.Name, recipe)
518→	if err != nil {
519→		resp.Status = "error"
520→		resp.Code = ErrInternalError
521→		resp.Message = fmt.Sprintf("generate failed: %v", err)
522→		return resp
523→	}
524→
525→	resp.Status = "generate"
526→	valCopy := json.RawMessage(value)
527→	resp.Value = &valCopy
528→	resp.GeneratorID = generatorID
529→	if outRecipe != nil {
530→		recipeCopy := json.RawMessage(outRecipe)
531→		resp.Recipe = &recipeCopy
532→	}
533→	return resp
534→}
535→
536→// Registry returns the generator registry, allowing custom builds to register
537→// native generators before calling Run().
538→func (h *Handler) Registry() *generators.Registry {
539→	return h.registry
540→}
541→
542→func (h *Handler) handleShutdown(resp Response) Response {
543→	h.registry.Close()
544→	h.setupLoader.Close()
545→	resp.Status = "shutdown_ack"
546→	return resp
547→}
548→
549→func (h *Handler) send(resp Response) error {
550→	data, err := json.Marshal(resp)
551→	if err != nil {
552→		return fmt.Errorf("marshaling response: %w", err)
553→	}
554→	line := string(data) + "\n"
555→	h.log.Log(context.Background(), LevelTrace, "Sent", "raw", string(data))
556→	_, err = io.WriteString(h.writer, line)
557→	return err
558→}
